@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_errorMessage
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">Total</div>
                    <div class="fs-5">@_allTasks.Count</div>
                </div>
            </div>
        </div>
        @foreach (var col in _columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@col</div>
                        <div class="fs-5">@GetTasksForColumn(col).Count</div>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">Overdue</div>
                    <div class="fs-5 text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</div>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (var i = 0; i < _columns.Length; i++)
        {
            var colIndex = i;
            var column = _columns[colIndex];
            var tasks = GetFilteredTasksForColumn(column);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="min-height: 200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <div class="fw-semibold mb-1">@task.Title</div>
                                    <div class="text-muted small mb-1">@task.Assignee</div>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <span class="text-muted small">@task.DueDate.ToString("MMM dd")</span>
                                    </div>
                                    <div class="d-flex justify-content-between mt-1">
                                        @if (colIndex > 0)
                                        {
                                            var leftStatus = _columns[colIndex - 1];
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, leftStatus)">
                                                &laquo; Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            var rightStatus = _columns[colIndex + 1];
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => MoveTaskAsync(task.Id, rightStatus)">
                                                Move Right &raquo;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_showForm.TryGetValue(column, out var show) && show)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_formTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_formAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_formPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="_formDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm"
                                                @onclick="() => SaveTaskAsync(column)">Save</button>
                                        <button class="btn btn-secondary btn-sm"
                                                @onclick="() => CancelForm(column)">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100"
                                @onclick="() => ShowAddForm(column)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _errorMessage;
    private string _searchTerm = string.Empty;

    // Inline form state
    private readonly Dictionary<string, bool> _showForm = new();
    private string _formTitle = string.Empty;
    private string _formAssignee = string.Empty;
    private string _formPriority = "Medium";
    private DateTime _formDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchTerm) ||
                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = _allTasks.First(t => t.Id == taskId);
            _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
    }

    private void ShowAddForm(string column)
    {
        // Reset form fields
        _formTitle = string.Empty;
        _formAssignee = string.Empty;
        _formPriority = "Medium";
        _formDueDate = DateTime.Today.AddDays(7);

        // Show only the clicked column's form
        foreach (var key in _showForm.Keys)
            _showForm[key] = false;
        _showForm[column] = true;
    }

    private void CancelForm(string column)
    {
        _showForm[column] = false;
    }

    private async Task SaveTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_formTitle))
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_formTitle, _formAssignee, _formPriority, _formDueDate);
            // The service creates tasks; if the status doesn't match the column, adjust locally
            var finalTask = created.Status == column ? created : created with { Status = column };
            _allTasks.Add(finalTask);
            _showForm[column] = false;
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
    }
}

